WITH ins AS (
  INSERT INTO t_p61016064_digital_innovation_i.dept_functions (project_id, dept_name, title, category, source_section_code)
  SELECT 1, 'Департамент финансового мониторинга (ДФМ)', v.title, v.category, v.code
  FROM (VALUES
    ('4.1.1','Разработка и актуализация ПВК по ПОД/ФТ, ЦПВК и программ их осуществления, а также иных внутренних документов Банка по вопросам ПОД/ФТ в части, касающейся деятельности Отдела методологии финансового мониторинга','methodology'),
    ('4.1.1','Рассмотрение и анализ поступающих на согласование внутренних нормативных и организационно-распорядительных документов Банка с целью обеспечения их соответствия требованиям ПВК по ПОД/ФТ и ЦПВК, а также законодательства Российской Федерации и нормативных актов Банка России в сфере ПОД/ФТ','methodology'),
    ('4.1.1','Подготовка документов и (или) информации и предоставление сведений для формирования ответов на письма (запросы, определения и тому подобное) Банка России по клиентам Банка','communication'),
    ('4.1.1','Подготовка документов и (или) информации для направления ответов на запросы правоохранительных органов по вопросам исполнения Федерального закона № 115-ФЗ','communication'),
    ('4.1.1','Осуществление мероприятий в рамках исполнения писем налоговых органов в связи с установлением фактов отсутствия юридического лица по адресу регистрации','control'),
    ('4.1.1','Подготовка проектов объяснений и пакета документов на постановления Банка России (определения, уведомления, телеграммы и иные документы) о возбуждении дел об административном правонарушении в части законодательства Российской Федерации и нормативных актов Банка России в сфере ПОД/ФТ','regulatory'),
    ('4.1.1','Получение информации от структурных подразделений, входящих в состав Подразделения, в целях подготовки Отчёта ежеквартального для курирующего заместителя Председателя Банка','control'),
    ('4.1.1','Получение информации от структурных подразделений в целях подготовки Отчёта ежегодного, согласованного с курирующим заместителем Председателя Банка, рекомендуемых мерах по улучшению системы ПОД/ФТ, для Наблюдательного совета Банка','control'),
    ('4.1.1','Согласование ключевых показателей эффективности работников УФМ СЦ','operational')
  ) AS v(code, title, category)
  RETURNING id, source_section_code
)
INSERT INTO t_p61016064_digital_innovation_i.function_org_units (function_id, org_unit_id, role, source_ref)
SELECT ins.id, u.id, 'owner', 'polozhenie'
FROM ins JOIN t_p61016064_digital_innovation_i.org_units u
  ON u.project_id = 1 AND u.code = ins.source_section_code AND u.is_archived = false;